    showSWOTAnalysis: function() {
        const competitors = store.state.competitors || [];
        const myItems = store.state.inventory?.length || 0;
        const myAvgPrice = store.state.inventory?.reduce((sum, i) => sum + (parseFloat(i.price) || 0), 0) / (myItems || 1);
        const compCount = competitors.length;
        const avgCompItems = compCount > 0 ? competitors.reduce((s, c) => s + (c.item_count || 0), 0) / compCount : 0;
        const avgCompPrice = compCount > 0 ? competitors.reduce((s, c) => s + (c.avg_price || 0), 0) / compCount : 0;

        const strengths = [];
        const weaknesses = [];
        const opportunities = [];
        const threats = [];

        if (myAvgPrice > avgCompPrice) strengths.push('Higher average price point — positioned as premium');
        else if (avgCompPrice > 0) weaknesses.push('Lower average price point than competitors');
        if (myItems > avgCompItems) strengths.push('Larger inventory than average competitor');
        else if (compCount > 0) weaknesses.push('Smaller inventory than average competitor');
        strengths.push('Multi-channel presence via VaultLister');
        strengths.push('Data-driven pricing with market intelligence');
        if (compCount < 5) opportunities.push('Low competitive density — room to grow');
        opportunities.push('Underserved niches identified in market gaps');
        opportunities.push('Cross-platform arbitrage on price differences');
        if (compCount > 10) threats.push('Crowded market segment — ' + compCount + ' tracked competitors');
        threats.push('Platform fee increases eroding margins');
        threats.push('Seasonal demand fluctuations');
        if (weaknesses.length === 0) weaknesses.push('Limited brand recognition vs. established sellers');

        const quadrant = (title, items, color, icon) => `
            <div style="background: ${color}; border-radius: 8px; padding: 16px;">
                <div style="font-weight: 600; margin-bottom: 8px; display: flex; align-items: center; gap: 6px;">
                    ${components.icon(icon, 16)} ${title}
                </div>
                <ul style="margin: 0; padding-left: 18px; font-size: 13px; line-height: 1.7;">
                    ${items.map(i => '<li>' + escapeHtml(i) + '</li>').join('')}
                </ul>
            </div>
        `;

        modals.show(`
            <div class="modal-header">
                <h2>SWOT Analysis</h2>
                <button class="modal-close" aria-label="Close" onclick="modals.close()">&times;</button>
            </div>
            <div class="modal-body">
                <p style="color: var(--gray-600); margin-bottom: 16px;">Based on ${compCount} tracked competitor${compCount !== 1 ? 's' : ''} and your current inventory.</p>
                <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 12px;">
                    ${quadrant('Strengths', strengths, 'var(--success-light, #ecfdf5)', 'trending-up')}
                    ${quadrant('Weaknesses', weaknesses, 'var(--error-light, #fef2f2)', 'alert-triangle')}
                    ${quadrant('Opportunities', opportunities, 'var(--info-light, #eff6ff)', 'star')}
                    ${quadrant('Threats', threats, 'var(--warning-light, #fffbeb)', 'shield')}
                </div>
            </div>
        `);
    },


