    // Settings handlers,


    showPredictionModelConfig: async function() {
        try {
            const res = await fetch('/api/predictions/models', { headers: { 'Authorization': `Bearer ${store.state.token}` } });
            if (!res.ok) throw new Error('Failed to load prediction models');
            const data = await res.json();
            const models = data.models || data || [];
            modals.show(`
                <div class="modal-header"><h3>Prediction Models</h3><button class="modal-close" aria-label="Close" onclick="modals.close()">&times;</button></div>
                <div class="modal-body">
                    <div style="margin-bottom: 16px;">
                        <button class="btn btn-primary btn-sm" onclick="handlers.showCreatePredictionModel()">+ New Model</button>
                    </div>
                    ${models.length > 0 ? models.map(m => `
                        <div class="card" style="padding: 12px; margin-bottom: 8px; display: flex; justify-content: space-between; align-items: center;">
                            <div><strong>${escapeHtml(m.name)}</strong><br><span class="badge">${escapeHtml(m.model_type)}</span> ${m.is_active ? '<span class="badge" style="background: var(--color-success);">Active</span>' : ''}</div>
                            <button class="btn btn-sm btn-danger" onclick="handlers.deletePredictionModel('${m.id}')">Delete</button>
                        </div>
                    `).join('') : '<p style="color: var(--text-secondary);">No custom models yet</p>'}
                </div>
            `);
        } catch (err) { toast.error('Failed to load models'); }
    },


    showCreatePredictionModel: function() {
        modals.show(`
            <div class="modal-header"><h3>Create Prediction Model</h3><button class="modal-close" aria-label="Close" onclick="modals.close()">&times;</button></div>
            <div class="modal-body">
                <div style="display: flex; flex-direction: column; gap: 12px;">
                    <div><label>Model Name</label><input type="text" id="model-name" class="form-input" placeholder="e.g., Holiday Season Predictor"></div>
                    <div><label>Model Type</label>
                        <select id="model-type" class="form-select">
                            <option value="linear">Linear Regression</option>
                            <option value="exponential">Exponential Growth</option>
                            <option value="seasonal">Seasonal Pattern</option>
                            <option value="moving_average">Moving Average</option>
                            <option value="weighted">Weighted Average</option>
                        </select>
                    </div>
                    <button class="btn btn-primary" onclick="handlers.createPredictionModel()">Create Model</button>
                </div>
            </div>
        `);
    },


    createPredictionModel: async function() {
        const name = document.getElementById('model-name')?.value;
        const model_type = document.getElementById('model-type')?.value;
        if (!name) return toast.error('Name is required');
        try {
            const res = await fetch('/api/predictions/models', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${store.state.token}`, 'x-csrf-token': store.state.csrfToken },
                body: JSON.stringify({ name, model_type })
            });
            if (res.ok) { toast.success('Model created'); handlers.showPredictionModelConfig(); }
        } catch (err) { toast.error('Failed to create model'); }
    },


    deletePredictionModel: async function(id) {
        try {
            await fetch(`/api/predictions/models/${id}`, { method: 'DELETE', headers: { 'Authorization': `Bearer ${store.state.token}`, 'x-csrf-token': store.state.csrfToken } });
            toast.success('Model deleted');
            handlers.showPredictionModelConfig();
        } catch (err) { toast.error('Failed to delete'); }
    },

    // What-If Scenario Analysis,


    showWhatIfScenario: function() {
        modals.show(`
            <div class="modal-header"><h3>What-If Scenario</h3><button class="modal-close" aria-label="Close" onclick="modals.close()">&times;</button></div>
            <div class="modal-body">
                <p>Adjust variables to see predicted outcomes:</p>
                <div style="display: grid; gap: 12px; margin: 16px 0;">
                    <div><label>Scenario Name</label><input type="text" id="scenario-name" class="form-input" placeholder="e.g., 20% price increase"></div>
                    <div><label>Price Change (%)</label><input type="number" id="scenario-price" class="form-input" value="0" step="5"></div>
                    <div><label>Volume Change (%)</label><input type="number" id="scenario-volume" class="form-input" value="0" step="5"></div>
                    <div><label>Season</label>
                        <select id="scenario-season" class="form-select">
                            <option value="normal">Normal</option>
                            <option value="holiday">Holiday Season</option>
                            <option value="summer">Summer</option>
                            <option value="back_to_school">Back to School</option>
                        </select>
                    </div>
                </div>
                <button class="btn btn-primary" style="width: 100%;" onclick="handlers.runWhatIfScenario()">Run Scenario</button>
                <div id="scenario-results" style="margin-top: 16px;"></div>
            </div>
        `);
    },


    runWhatIfScenario: async function() {
        const name = document.getElementById('scenario-name')?.value || 'Untitled';
        const price_change = parseFloat(document.getElementById('scenario-price')?.value) || 0;
        const volume_change = parseFloat(document.getElementById('scenario-volume')?.value) || 0;
        const season = document.getElementById('scenario-season')?.value || 'normal';
        try {
            const res = await fetch('/api/predictions/scenarios', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${store.state.token}`, 'x-csrf-token': store.state.csrfToken },
                body: JSON.stringify({ name, base_data: {}, adjustments: { price_change, volume_change, season } })
            });
            if (!res.ok) throw new Error('Failed to run scenario');
            const data = await res.json();
            const r = data.results || {};
            // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
            document.getElementById('scenario-results').innerHTML = sanitizeHTML(`
                <div class="card" style="padding: 16px;">
                    <h4>Scenario Results</h4>
                    <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 8px; margin-top: 12px;">
                        <div><strong>Projected Revenue:</strong> $${(r.projected_revenue || 0).toFixed(2)}</div>
                        <div><strong>Revenue Change:</strong> ${r.revenue_change_pct || 0}%</div>
                        <div><strong>Projected Volume:</strong> ${r.projected_volume || 0} units</div>
                        <div><strong>Impact:</strong> <span class="badge">${r.impact_level || 'moderate'}</span></div>
                    </div>
                </div>
            `);
        } catch (err) { document.getElementById('scenario-results').innerHTML = sanitizeHTML('<p style="color: var(--text-error);">Failed to run scenario</p>'); }  // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
    },

    // Set Acquired Date for Inventory Item,


    deleteSupplier: async function(id, name) {
        if (!confirm('Delete supplier "' + name + '"?')) return;
        try {
            await api.ensureCSRFToken();
            await api.delete('/inventory/suppliers/' + id);
            toast.success('Supplier deleted');
            handlers.showSupplierManager();
        } catch (e) {
            toast.error('Failed to delete supplier');
        }
    },

